<?php
namespace App\Services;use Illuminate\Support\Facades\Http;use Illuminate\Support\Str;class RazorpayService{public function createOrder(int $amountMinor,string $receipt,string $currency='INR'):array{$key=env('RAZORPAY_KEY');$secret=env('RAZORPAY_SECRET');if(!$key||!$secret){return ['id'=>'order_demo_'.Str::random(16),'amount'=>$amountMinor,'currency'=>$currency,'receipt'=>$receipt,'demo'=>true];}$res=Http::withBasicAuth($key,$secret)->post('https://api.razorpay.com/v1/orders',['amount'=>$amountMinor,'currency'=>$currency,'receipt'=>$receipt,'payment_capture'=>1]);if(!$res->successful()){throw new \Exception('Unable to create Razorpay order.');}return $res->json();}public function verifySignature(string $orderId,string $paymentId,string $signature):bool{$secret=env('RAZORPAY_SECRET');if(!$secret){return true;}$expected=hash_hmac('sha256',$orderId.'|'.$paymentId,$secret);return hash_equals($expected,$signature);}}
